namespace sv_30e04884f47e4d88b798071d8dbfa974.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings

<nav class="settings-sidebar">
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li class="settings-nav-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="nav-icon">@GetIcon(section)</span>
                <span class="nav-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings
@using sv_30e04884f47e4d88b798071d8dbfa974.Services

<div class="settings-section">
    <h2>Profile Settings</h2>

    @if (ShowSuccess)
    {
        <div class="toast success">Profile saved successfully!</div>
    }

    <div class="avatar-preview">
        @if (!string.IsNullOrEmpty(EditDisplayName))
        {
            <img src="@EditAvatarUrl" alt="Avatar" class="avatar-image" />
        }
        <p class="avatar-url">@EditAvatarUrl</p>
    </div>

    <div class="form-group">
        <label for="displayName">Display Name</label>
        <input id="displayName" type="text" @bind="EditDisplayName" class="form-control" />
    </div>

    <div class="form-group">
        <label for="email">Email</label>
        <input id="email" type="email" @bind="EditEmail" class="form-control" />
    </div>

    <div class="form-group">
        <label for="bio">Bio</label>
        <textarea id="bio" @bind="EditBio" class="form-control" rows="4"></textarea>
    </div>

    <div class="form-group">
        <label for="avatarUrl">Avatar URL</label>
        <input id="avatarUrl" type="url" @bind="EditAvatarUrl" class="form-control" />
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-secondary" @onclick="DiscardChanges">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string EditDisplayName = "";
    private string EditEmail = "";
    private string EditBio = "";
    private string EditAvatarUrl = "";
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !HasLocalEdits)
        {
            ResetToProfile();
        }
    }

    private bool HasLocalEdits;

    private void ResetToProfile()
    {
        if (Profile is null) return;
        EditDisplayName = Profile.DisplayName;
        EditEmail = Profile.Email;
        EditBio = Profile.Bio;
        EditAvatarUrl = Profile.AvatarUrl;
        HasLocalEdits = false;
    }

    private async Task SaveChanges()
    {
        IsSaving = true;
        var updated = new UserProfile(EditDisplayName, EditEmail, EditAvatarUrl, EditBio);
        await OnSave.InvokeAsync(updated);
        HasLocalEdits = false;
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }

    private void DiscardChanges()
    {
        ResetToProfile();
        ShowSuccess = false;
    }
}

@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings
@using sv_30e04884f47e4d88b798071d8dbfa974.Services

<div class="settings-section">
    <h2>Notification Preferences</h2>

    @if (ShowSuccess)
    {
        <div class="toast success">Preferences saved successfully!</div>
    }

    <div class="toggle-group">
        <label class="toggle-label">
            <input type="checkbox" @bind="EmailNotifications" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Email Notifications</span>
        </label>

        <label class="toggle-label">
            <input type="checkbox" @bind="PushNotifications" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Push Notifications</span>
        </label>

        <label class="toggle-label">
            <input type="checkbox" @bind="WeeklyDigest" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Weekly Digest</span>
        </label>
    </div>

    <h3>Muted Channels</h3>
    <div class="channel-list">
        @if (AvailableChannels is not null)
        {
            @foreach (var channel in AvailableChannels)
            {
                <label class="channel-item">
                    <input type="checkbox"
                           checked="@MutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <span>@channel</span>
                </label>
            }
        }
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SavePreferences" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Preferences")
        </button>
    </div>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
    [Parameter] public List<string>? AvailableChannels { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = new();
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = new List<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!isMuted)
            MutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        IsSaving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, MutedChannels);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }
}

@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings
@using sv_30e04884f47e4d88b798071d8dbfa974.Services

<div class="settings-section">
    <h2>Security Settings</h2>

    @if (!string.IsNullOrEmpty(Message))
    {
        <div class="toast @(IsError ? "error" : "success")">@Message</div>
    }

    <!-- Change Password Panel -->
    <div class="expandable-panel">
        <button class="panel-header" @onclick="() => PasswordPanelOpen = !PasswordPanelOpen">
            <span>Change Password</span>
            <span class="expand-icon">@(PasswordPanelOpen ? "▼" : "▶")</span>
        </button>

        @if (PasswordPanelOpen)
        {
            <div class="panel-body">
                <div class="form-group">
                    <label for="currentPassword">Current Password</label>
                    <input id="currentPassword" type="password" @bind="CurrentPassword" class="form-control" />
                </div>
                <div class="form-group">
                    <label for="newPassword">New Password</label>
                    <input id="newPassword" type="password" @bind="NewPassword" class="form-control" />
                </div>
                <div class="form-group">
                    <label for="confirmPassword">Confirm Password</label>
                    <input id="confirmPassword" type="password" @bind="ConfirmPassword" class="form-control" />
                </div>
                <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@IsUpdatingPassword">
                    @(IsUpdatingPassword ? "Updating..." : "Update Password")
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="twofa-section">
        <h3>Two-Factor Authentication</h3>
        <div class="twofa-status">
            <span class="status-indicator @(Settings?.TwoFactorEnabled == true ? "enabled" : "disabled")"></span>
            <span>@(Settings?.TwoFactorEnabled == true ? "Enabled" : "Disabled")</span>
        </div>
        <label class="toggle-label">
            <input type="checkbox" checked="@(Settings?.TwoFactorEnabled ?? false)"
                   @onchange="Toggle2FA" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Enable Two-Factor Authentication</span>
        </label>
        @if (Settings?.LastPasswordChange is not null)
        {
            <p class="last-changed">Last password change: @Settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</p>
        }
    </div>

    <!-- Active Sessions -->
    <div class="sessions-section">
        <h3>Active Sessions</h3>
        @if (Settings?.Sessions is not null)
        {
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Settings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("MMM dd, yyyy HH:mm")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-danger btn-sm"
                                            @onclick="() => ConfirmRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="current-session-badge">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (SessionToRevoke is not null)
    {
        <div class="dialog-overlay" @onclick="CancelRevoke">
            <div class="dialog" @onclick:stopPropagation="true">
                <h4>Revoke Session</h4>
                <p>Are you sure you want to revoke the session on <strong>@SessionToRevoke.Device</strong> from <strong>@SessionToRevoke.Location</strong>?</p>
                <div class="dialog-actions">
                    <button class="btn btn-danger" @onclick="ExecuteRevoke">Revoke</button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool PasswordPanelOpen;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private bool IsUpdatingPassword;
    private string Message = "";
    private bool IsError;
    private ActiveSession? SessionToRevoke;

    private async Task UpdatePassword()
    {
        if (NewPassword != ConfirmPassword)
        {
            Message = "New password and confirmation do not match.";
            IsError = true;
            return;
        }

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            Message = "All password fields are required.";
            IsError = true;
            return;
        }

        IsUpdatingPassword = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            Message = "Password updated successfully!";
            IsError = false;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
            PasswordPanelOpen = false;
        }
        catch (Exception ex)
        {
            Message = $"Failed to update password: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsUpdatingPassword = false;
            _ = HideMessageAfterDelay();
        }
    }

    private void ConfirmRevoke(ActiveSession session) => SessionToRevoke = session;
    private void CancelRevoke() => SessionToRevoke = null;

    private async Task ExecuteRevoke()
    {
        if (SessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(SessionToRevoke.Id);
            SessionToRevoke = null;
        }
    }

    private async Task Toggle2FA(ChangeEventArgs e)
    {
        var enabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(enabled);
    }

    private async Task HideMessageAfterDelay()
    {
        await Task.Delay(3000);
        Message = "";
        StateHasChanged();
    }
}

