@code {
    [Parameter] public SecuritySettings? Settings { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<(string currentPassword, string newPassword)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool PasswordPanelOpen;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private bool IsUpdatingPassword;
    private string Message = "";
    private bool IsError;
    private ActiveSession? SessionToRevoke;

    private async Task UpdatePassword()
    {
        if (NewPassword != ConfirmPassword)
        {
            Message = "New password and confirmation do not match.";
            IsError = true;
            return;
        }

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            Message = "All password fields are required.";
            IsError = true;
            return;
        }

        IsUpdatingPassword = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            Message = "Password updated successfully!";
            IsError = false;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
            PasswordPanelOpen = false;
        }
        catch (Exception ex)
        {
            Message = $"Failed to update password: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsUpdatingPassword = false;
            _ = HideMessageAfterDelay();
        }
    }

    private void ConfirmRevoke(ActiveSession session) => SessionToRevoke = session;
    private void CancelRevoke() => SessionToRevoke = null;

    private async Task ExecuteRevoke()
    {
        if (SessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(SessionToRevoke.Id);
            SessionToRevoke = null;
        }
    }

    private async Task Toggle2FA(ChangeEventArgs e)
    {
        var enabled = (bool)(e.Value ?? false);
        await OnToggle2FA.InvokeAsync(enabled);
    }

    private async Task HideMessageAfterDelay()
    {
        await Task.Delay(3000);
        Message = "";
        StateHasChanged();
    }
}

