@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings

<nav class="settings-sidebar">
    <ul class="settings-nav">
        @foreach (var section in Sections)
        {
            <li class="settings-nav-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="nav-icon">@GetIcon(section)</span>
                <span class="nav-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings
@using sv_30e04884f47e4d88b798071d8dbfa974.Services

<div class="settings-section">
    <h2>Profile Settings</h2>

    @if (ShowSuccess)
    {
        <div class="toast success">Profile saved successfully!</div>
    }

    <div class="avatar-preview">
        @if (!string.IsNullOrEmpty(EditDisplayName))
        {
            <img src="@EditAvatarUrl" alt="Avatar" class="avatar-image" />
        }
        <p class="avatar-url">@EditAvatarUrl</p>
    </div>

    <div class="form-group">
        <label for="displayName">Display Name</label>
        <input id="displayName" type="text" @bind="EditDisplayName" class="form-control" />
    </div>

    <div class="form-group">
        <label for="email">Email</label>
        <input id="email" type="email" @bind="EditEmail" class="form-control" />
    </div>

    <div class="form-group">
        <label for="bio">Bio</label>
        <textarea id="bio" @bind="EditBio" class="form-control" rows="4"></textarea>
    </div>

    <div class="form-group">
        <label for="avatarUrl">Avatar URL</label>
        <input id="avatarUrl" type="url" @bind="EditAvatarUrl" class="form-control" />
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-secondary" @onclick="DiscardChanges">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string EditDisplayName = "";
    private string EditEmail = "";
    private string EditBio = "";
    private string EditAvatarUrl = "";
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !HasLocalEdits)
        {
            ResetToProfile();
        }
    }

    private bool HasLocalEdits;

    private void ResetToProfile()
    {
        if (Profile is null) return;
        EditDisplayName = Profile.DisplayName;
        EditEmail = Profile.Email;
        EditBio = Profile.Bio;
        EditAvatarUrl = Profile.AvatarUrl;
        HasLocalEdits = false;
    }

    private async Task SaveChanges()
    {
        IsSaving = true;
        var updated = new UserProfile(EditDisplayName, EditEmail, EditAvatarUrl, EditBio);
        await OnSave.InvokeAsync(updated);
        HasLocalEdits = false;
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }

    private void DiscardChanges()
    {
        ResetToProfile();
        ShowSuccess = false;
    }
}

