@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings
@using sv_30e04884f47e4d88b798071d8dbfa974.Services

<div class="settings-section">
    <h2>Notification Preferences</h2>

    @if (ShowSuccess)
    {
        <div class="toast success">Preferences saved successfully!</div>
    }

    <div class="toggle-group">
        <label class="toggle-label">
            <input type="checkbox" @bind="EmailNotifications" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Email Notifications</span>
        </label>

        <label class="toggle-label">
            <input type="checkbox" @bind="PushNotifications" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Push Notifications</span>
        </label>

        <label class="toggle-label">
            <input type="checkbox" @bind="WeeklyDigest" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Weekly Digest</span>
        </label>
    </div>

    <h3>Muted Channels</h3>
    <div class="channel-list">
        @if (AvailableChannels is not null)
        {
            @foreach (var channel in AvailableChannels)
            {
                <label class="channel-item">
                    <input type="checkbox"
                           checked="@MutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <span>@channel</span>
                </label>
            }
        }
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SavePreferences" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save Preferences")
        </button>
    </div>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }
    [Parameter] public List<string>? AvailableChannels { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = new();
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = new List<string>(Prefs.MutedChannels);
        }
    }

    private void ToggleChannel(string channel, bool isMuted)
    {
        if (isMuted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!isMuted)
            MutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        IsSaving = true;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, MutedChannels);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }
}

