@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings
@using sv_30e04884f47e4d88b798071d8dbfa974.Services

<div class="settings-section">
    <h2>Appearance Settings</h2>

    @if (ShowSuccess)
    {
        <div class="toast success">Appearance saved successfully!</div>
    }

    <!-- Theme Selector -->
    <div class="form-group">
        <label>Theme</label>
        <div class="radio-group">
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <label class="radio-label">
                    <input type="radio" name="theme" value="@theme"
                           checked="@(SelectedTheme == theme)"
                           @onchange="() => SelectedTheme = theme" />
                    <span>@theme</span>
                </label>
            }
        </div>
    </div>

    <!-- Font Size Selector -->
    <div class="form-group">
        <label>Font Size</label>
        <div class="radio-group">
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <label class="radio-label">
                    <input type="radio" name="fontSize" value="@size"
                           checked="@(SelectedFontSize == size)"
                           @onchange="() => SelectedFontSize = size" />
                    <span>@size</span>
                </label>
            }
        </div>
    </div>

    <!-- Language Dropdown -->
    <div class="form-group">
        <label for="language">Language</label>
        <select id="language" @bind="SelectedLanguage" class="form-control">
            <option value="en">English</option>
            <option value="es">Español</option>
            <option value="fr">Français</option>
            <option value="de">Deutsch</option>
            <option value="ja">日本語</option>
            <option value="zh">中文</option>
        </select>
    </div>

    <!-- Compact Mode -->
    <div class="form-group">
        <label class="toggle-label">
            <input type="checkbox" @bind="CompactMode" class="toggle-input" />
            <span class="toggle-switch"></span>
            <span>Compact Mode</span>
        </label>
    </div>

    <!-- Live Preview -->
    <div class="preview-area @GetPreviewClasses()">
        <h4>Live Preview</h4>
        <p class="preview-text">This is how your content will look with the selected settings.</p>
        <div class="preview-card">
            <span class="preview-heading">Sample Heading</span>
            <span class="preview-body">Sample body text to demonstrate font size and theme.</span>
        </div>
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@IsSaving">
            @(IsSaving ? "Saving..." : "Save")
        </button>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string SelectedTheme = "System";
    private string SelectedFontSize = "Medium";
    private string SelectedLanguage = "en";
    private bool CompactMode;
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Settings is not null)
        {
            SelectedTheme = Settings.Theme;
            SelectedFontSize = Settings.FontSize;
            SelectedLanguage = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = $"theme-{SelectedTheme.ToLowerInvariant()} font-{SelectedFontSize.ToLowerInvariant()}";
        if (CompactMode) classes += " compact";
        return classes;
    }

    private async Task SaveAppearance()
    {
        IsSaving = true;
        var updated = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        StateHasChanged();
    }
}

