@page "/settings"
@namespace sv_30e04884f47e4d88b798071d8dbfa974.Components.Pages.Settings
@using sv_30e04884f47e4d88b798071d8dbfa974.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-page">
    <SettingsSidebar ActiveSection="@ActiveSection" OnSectionChanged="SetActiveSection" />

    <main class="settings-content">
        @if (IsLoading)
        {
            <div class="loading">Loading settings...</div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "Profile":
                    <ProfileSection Profile="@Profile" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@NotificationPrefs"
                                          AvailableChannels="@AvailableChannels"
                                          OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Settings="@Security"
                                     CurrentSessionId="@CurrentSessionId"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession"
                                     OnToggle2FA="Toggle2FA" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@Appearance" OnSave="SaveAppearance" />
                    break;
            }
        }
    </main>
</div>

@code {
    private string ActiveSection = "Profile";
    private bool IsLoading = true;

    private UserProfile? Profile;
    private NotificationPrefs? NotificationPrefs;
    private SecuritySettings? Security;
    private AppearanceSettings? Appearance;

    private string CurrentSessionId = "current";
    private List<string> AvailableChannels = new() { "General", "Marketing", "Engineering", "Design", "Support", "Sales" };

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        IsLoading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        Profile = profileTask.Result;
        NotificationPrefs = notifTask.Result;
        Security = securityTask.Result;
        Appearance = appearanceTask.Result;

        if (Security?.Sessions.Count > 0)
        {
            CurrentSessionId = Security.Sessions[0].Id;
        }
    }

    private void SetActiveSection(string section) => ActiveSection = section;

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        Profile = profile;
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        NotificationPrefs = prefs;
    }

    private async Task ChangePassword((string currentPassword, string newPassword) args)
    {
        await SettingsService.ChangePasswordAsync(args.currentPassword, args.newPassword);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private Task Toggle2FA(bool enabled)
    {
        // In a real app, this would call a service method
        if (Security is not null)
        {
            Security = Security with { TwoFactorEnabled = enabled };
        }
        return Task.CompletedTask;
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        Appearance = settings;
    }
}

