namespace sv_30e04884f47e4d88b798071d8dbfa974.Services;

public class InMemorySettingsService : ISettingsService
{
    private UserProfile _profile = new("Jane Doe", "jane@example.com", "https://i.pravatar.cc/150?img=5", "Software engineer and open-source enthusiast.");
    private NotificationPrefs _notifs = new(true, true, false, new List<string> { "Marketing" });
    private SecuritySettings _security = new(false, DateTime.UtcNow.AddDays(-30), new List<ActiveSession>
    {
        new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
        new("sess-2", "Safari on iPhone", "New York, US", DateTime.UtcNow.AddHours(-2)),
        new("sess-3", "Firefox on Linux", "London, UK", DateTime.UtcNow.AddDays(-1)),
